// And groups predicates with the AND operator between them.
func And(predicates ...predicate.SupportThread) predicate.SupportThread {
	return predicate.SupportThread(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.SupportThread) predicate.SupportThread {
	return predicate.SupportThread(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.SupportThread) predicate.SupportThread {
	return predicate.SupportThread(sql.NotPredicates(p))
}
